      "challenge_complete": "An kammala ƙalubale!",
      "206_bones_support_protection_movement_": "Ƙasusuwa 206 — tallafi, kariya, motsi, ajiyar ma’adinai, ƙirƙirar jini.",
      "houses_meninges_brain_and_cranial_nerv": "Yana ɗauke da meninges, ƙwaƙwalwa, da ramukan jijiyoyin kwanya. Ɗinke (coronal, sagittal, lambdoid) suna haɗuwa sa’ad da yaro ya kai shekara 2.",
      "ribs_1_12": "Haƙarƙari (1-12)",
      "hyoid_bone": "Ƙashin Hyoid",
      "atlas_c1_axis_c2": "Atlas (C1) da Axis (C2)",
      "metatarsals_phalanges_foot": "Metatarsals da Phalanges (Ƙafa)",
      "metacarpals_phalanges_hand": "Metacarpals da Phalanges (Hannu)",
      "scaphoid_bone": "Ƙashin Scaphoid",
      "600_muscles_movement_posture_heat_prod": "Tsokoki 600+ — motsi, tsayuwa, ƙirƙirar zafi, daidaita gaɓoɓi.",
      "rotator_cuff_sits": "Rotator Cuff (SITS)",
      "iliopsoas": "Iliopsoas",
      "intercostal_muscles": "Tsokokin Tsakanin Haƙarƙari",
      "pelvic_floor_levator_ani": "Ƙasan Ƙugu (Levator Ani)",
      "diaphragm_muscle": "Diaphragm (Tsoka)",
      "heart_60_000_miles_of_vessels_5l_of_bl": "Zuciya, mil 60,000 na jijiyoyi, lita 5 na jini — tana kai O₂, abinci mai gina jiki, hormones; tana cire shara.",
      "circle_of_willis": "Circle of Willis",
      "great_saphenous_vein": "Babbar Jijiyar Saphenous",
      "lymphatic_vessels": "Jijiyoyin Lymph",
      "cns_brain_spinal_cord_and_pns_31_spina": "CNS (ƙwaƙwalwa + kashin baya) da PNS (nau’i 31 na jijiyoyin baya, nau’i 12 na jijiyoyin kwanya, tsarin jijiya mai sarrafa kansa).",
      "lightest_sleep_transition_from_wakeful": "Barci mafi sauƙi — sauyi daga farkawa. Motsin idanu a hankali, ƙarfin tsoka yana raguwa. Girgizar hypnic (motsin myoclonic) na kowa. Ana farkar da sauƙi. Manyan raƙuman vertex suna bayyana a EEG.",
      "true_sleep_begins_core_body_temperatur": "Barci na gaskiya yana farawa. Zafin cikin jiki yana sauka, bugun zuciya yana raguwa. Sleep spindles (fashewar thalamocortical) suna kare barci da ƙarfafa ƙwaƙwalwar motsi. K-complexes manyan raƙuma ne masu amsa abubuwan waje.",
      "deep_slow_wave_sleep_sws_most_restorat": "Barci mai zurfi/na raƙuma masu jinkiri (SWS). Matakin mai maido da ƙarfi sosai. Fitar hormone na girma tana kaiwa kololuwa. Tsarin glymphatic yana tsaftace sharar ƙwaƙwalwa (amyloid-β). Ƙarfafa ƙwaƙwalwar bayyanawa yana faruwa. Mafi wahalar farkawa; nauyin barci idan an farkar.",
      "dreaming_stage_brain_is_highly_active_": "Matakin mafarki. Ƙwaƙwalwa tana aiki sosai (kamar farkawa) amma jiki ya shanye (atonia ta hanyar hanawar tushen kwakwalwa na jijiyoyin motsi). Motsin idanu masu sauri da daidaituwa. Sarrafa ƙwaƙwalwar motsin rai da warware matsala ta ƙirƙira. Zagayoyin suna tsawaita yayin da dare ke ci gaba.",
      "cerebral_cortex_4_lobes": "Bawon Ƙwaƙwalwa (Loba 4)",
      "brodmann_areas_map_52_cytoarchitectura": "Yankunan Brodmann suna zana yankuna 52 na tsarin sel. Babban bawon motsi (yanki 4), babban bawon ji na jiki (yanki 3,1,2), babban bawon gani (yanki 17), babban bawon ji (yanki 41,42). Bawon prefrontal shi ne na ƙarshe da ke samun myelin (~shekara 25).",
      "purkinje_cells_are_among_the_largest_n": "Selolin Purkinje na cikin manyan jijiyoyi, kowanne yana karɓar kimanin 200,000 na shigar synaptic. Bawon cerebellar yana da yadudduka 3: molecular, Purkinje, granular. Sabon bincike yana nuna rawar da suke takawa a fahimta, motsin rai, da harshe.",
      "brainstem_midbrain_pons_medulla": "Tushen Ƙwaƙwalwa (Tsakiyar Ƙwaƙwalwa, Pons, Medulla)",
      "contains_nuclei_for_cranial_nerves_iii": "Yana ɗauke da nuclei na jijiyoyin kwanya III–XII. Tsarin reticular activating (RAS) shi ne \"maɓallin kunna\" na ƙwaƙwalwa — lalacewa tana haddasa suma. Ratsawar piramid a medulla: haɗuwar motsi tana bayyana sarrafa motsi na gefen gaba.",
      "memory_replay_during_sleep_hippocampal": "Sake kunna ƙwaƙwalwa lokacin barci: jijiyoyin hippocampal suna \"sake kunna\" abubuwan da suka faru da rana lokacin barcin N3, suna canja ƙwaƙwalwa zuwa neocortex. Selolin grid a bawon entorhinal suna ba selolin wuri na hippocampal alkiblar sarari.",
      "fear_conditioning_pathway_auditory_cor": "Hanyar koyar da tsoro: bawon ji → amygdala na gefe → amygdala na tsakiya → hypothalamus (amsar damuwa) + PAG (daskarewa). Mu’amalar amygdala-prefrontal tana ba da damar sarrafa motsin rai — tushen maganin CBT.",
      "key_nuclei_vpl_vpm_somatosensory_relay": "Muhimman nuclei: VPL/VPM (mika ji na jiki), LGN (mika gani zuwa V1), MGN (mika ji zuwa A1), pulvinar (hankali), rukunin nuclei na gaba (ƙwaƙwalwa, da’irar Papez).",
      "thermostat_analogy_anterior_hypothalam": "Misalin thermostat: hypothalamus na gaba yana haddasa sanyaya (faɗaɗa jijiyoyi, gumi); hypothalamus na baya yana haddasa ɗumama (rawar jiki, matsewar jijiyoyi). Zazzaɓi = ɗagattar matakin da prostaglandins ke yi daga kamuwa da cuta.",
      "split_brain_experiments_revealed_hemis": "Gwaje-gwajen raba ƙwaƙwalwa sun bayyana ƙwarewar sassan biyu: sashe na hagu = harshe, dabaru; sashe na dama = sarrafa sarari, na gaba ɗaya. Bayanin da aka nuna wa filin gani ɗaya ana sarrafa shi ta sashe na gefen gaba.",
      "dopamine_from_substantia_nigra_modulat": "Dopamine daga substantia nigra yana sarrafa hanyoyin kai tsaye (D1, mai kuzari) da na kaikaice (D2, mai hanawa). Rasa wannan sarrafawa a Parkinson yana haddasa wahalar fara motsi ta musamman.",
      "cranial_nerves_i_xii": "Jijiyoyin Kwanya (I-XII)",
      "returns_interstitial_fluid_absorbs_die": "Yana mayar da ruwan tsakanin sel, yana shan kitsen abinci, sa ido na garkuwar jiki — ƙwayoyin lymph 600–700, thymus, saifa.",
